"use client";
import { useState, useCallback } from "react";

export type FreighterState = {
  isInstalled: boolean;
  isConnected: boolean;
  publicKey: string | null;
  error: string | null;
};

export function useFreighter() {
  const [state, setState] = useState<FreighterState>({
    isInstalled: false,
    isConnected: false,
    publicKey: null,
    error: null,
  });

  const connect = useCallback(async (): Promise<string | null> => {
    try {
      // Dynamic import — SSR'da window yok
      const freighter = await import("@stellar/freighter-api");

      const installed = await freighter.isConnected();
      if (!installed.isConnected) {
        setState((s) => ({
          ...s,
          isInstalled: false,
          error: "Freighter yüklü değil. freighter.app adresinden indir.",
        }));
        return null;
      }

      const allowed = await freighter.isAllowed();
      if (!allowed.isAllowed) {
        await freighter.setAllowed();
      }

      const { address } = await freighter.getAddress();
      setState({
        isInstalled: true,
        isConnected: true,
        publicKey: address,
        error: null,
      });
      return address;
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Cüzdan bağlanamadı";
      setState((s) => ({ ...s, error: msg }));
      return null;
    }
  }, []);

  const signChallenge = useCallback(
    async (challenge: string): Promise<string | null> => {
      try {
        const freighter = await import("@stellar/freighter-api");

        // signMessage ile challenge imzala.
        // NOT: signMessage Freighter API'sinde henüz tam stabil olmayabilir.
        // Eğer signMessage mevcut değilse, alternatif olarak signTransaction ile
        // challenge'ı memo'ya gömmüş dummy bir Stellar transaction imzalanabilir:
        //   const { signTransaction } = freighter;
        //   const dummyTx = buildDummyTxWithMemo(challenge, networkPassphrase);
        //   const { signedTransaction } = await signTransaction(dummyTx, { networkPassphrase });
        //   return signedTransaction;
        const freighterAny = freighter as Record<string, unknown>;
        if (typeof freighterAny.signMessage !== "function") {
          setState((s) => ({
            ...s,
            error: "Freighter sürümünüz signMessage desteklemiyor. Lütfen güncelleyin.",
          }));
          return null;
        }

        const result = (await (freighterAny.signMessage as Function)(challenge, {
          networkPassphrase: "Test SDF Network ; September 2015",
        })) as { signedMessage?: string };

        return result.signedMessage ?? null;
      } catch (err) {
        const msg = err instanceof Error ? err.message : "İmzalama başarısız";
        setState((s) => ({ ...s, error: msg }));
        return null;
      }
    },
    []
  );

  return { ...state, connect, signChallenge };
}
